section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/prometheus-monitoring.json",
  "type": "object",
  "required": [
    "metric_name",
    "metric_type",
    "labels",
    "help_text",
    "unit",
    "scrape_interval_seconds",
    "recording_rules",
    "alerts"
  ],
  "properties": {
    "metric_name": {
      "type": "string",
      "description": "string (snake_case, namespace_name_unit_suffix)"
    },
    "metric_type": {
      "type": "string",
      "description": "enum (counter | gauge | histogram | summary)"
    },
    "labels": {
      "type": "array",
      "description": "array (length \u226410, bounded value sets)"
    },
    "help_text": {
      "type": "string",
      "description": "string (\u2264200 chars)"
    },
    "unit": {
      "type": "string",
      "description": "string (seconds | bytes | ratio | none)"
    },
    "scrape_interval_seconds": {
      "type": "integer",
      "description": "integer (>=10)"
    },
    "recording_rules": {
      "type": "array",
      "description": "array (optional, name format level:metric:operation)"
    },
    "alerts": {
      "type": "array",
      "description": "array (each with runbook_url + for_duration)"
    }
  }
}

example.code:
{
  "metric_name": "http_requests_total",
  "metric_type": "counter",
  "labels": [
    "method",
    "status_class",
    "service"
  ],
  "help_text": "Total HTTP requests by method, status class, service.",
  "unit": "none",
  "scrape_interval_seconds": 15,
  "recording_rules": [
    "job:http_requests:rate5m"
  ],
  "alerts": [
    {
      "name": "HighErrorRate",
      "for_duration": "5m",
      "runbook_url": "https://runbooks/http-errors"
    }
  ]
}
